public class Main {
    interface Transformer<T> {
        T transform(T input);
        default Transformer<T> andThen(Transformer<T> next) {
            // Chain: apply this transform, then next
            return input -> next.transform(this.transform(input));
        }
        static <T> Transformer<T> identity() { return t -> t; }
    }
    public static void main(String[] args) {
        Transformer<String> trim = String::trim;
        Transformer<String> upper = String::toUpperCase;
        Transformer<String> clean = trim.andThen(upper);
        System.out.println(clean.transform("  hello world  "));
    }
}

